http:request.http:query-params:
#[output application/java --- {
    ("\$skip"): vars.offset,
    ("\$top"): vars.limit
} ++ (if (vars.statusFilter != '') {("\$filter"): "OverallSDProcessStatus eq '" ++ vars.statusFilter ++ "'"} else {})]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    success: false,
    errorCode: "SAP_CONNECTIVITY_ERROR",
    message: "Unable to connect to SAP ERP system",
    correlationId: vars.correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}

%dw 2.0
output application/json
---
{
    success: false,
    errorCode: "VALIDATION_ERROR",
    message: error.description,
    correlationId: vars.correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}

%dw 2.0
output application/json
var sapOrder = payload.d
---
{
    orderId: sapOrder.SalesOrder default "",
    orderType: sapOrder.SalesOrderType default "",
    salesOrganization: sapOrder.SalesOrganization default "",
    distributionChannel: sapOrder.DistributionChannel default "",
    division: sapOrder.OrganizationDivision default "",
    customer: {
        id: sapOrder.SoldToParty default "",
        purchaseOrderNumber: sapOrder.PurchaseOrderByCustomer default ""
    },
    pricing: {
        netAmount: sapOrder.TotalNetAmount as Number default 0,
        currency: sapOrder.TransactionCurrency default "USD",
        taxAmount: sapOrder.TaxAmount as Number default 0
    },
    status: {
        overall: sapOrder.OverallSDProcessStatus default "",
        delivery: sapOrder.OverallDeliveryStatus default "",
        billing: sapOrder.OverallBillingStatus default ""
    },
    dates: {
        created: sapOrder.CreationDate default "",
        requested: sapOrder.RequestedDeliveryDate default "",
        validFrom: sapOrder.SalesOrderDate default ""
    },
    lineItems: (sapOrder.to_Item.results default []) map ((item, idx) -> {
        itemNumber: item.SalesOrderItem default "",
        materialNumber: item.Material default "",
        description: item.SalesOrderItemText default "",
        quantity: item.RequestedQuantity as Number default 0,
        unit: item.RequestedQuantityUnit default "EA",
        netAmount: item.NetAmount as Number default 0,
        plant: item.Plant default "",
        storageLocation: item.StorageLocation default ""
    }),
    metadata: {
        correlationId: vars.correlationId,
        retrievedAt: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"},
        source: "SAP_ERP"
    }
}

%dw 2.0
output application/json
---
{
    success: false,
    errorCode: "ORDER_NOT_FOUND",
    message: "SAP order '" ++ vars.orderId ++ "' was not found",
    correlationId: vars.correlationId,
    timestamp: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss.SSSZ"}
}

http:request.http:query-params:
#[output application/java --- {
    ("\$top"): attributes.queryParams.limit default "50"
} ++ (if (vars.searchTerm != '') {("\$filter"): "substringof('" ++ vars.searchTerm ++ "', ProductDescription)"} else {})]

#[output application/java --- {
    ("\$top"): attributes.queryParams.limit default "50",
    ("\$filter"): "BusinessPartnerCategory eq '1'" ++ (if (vars.customerSearch != '') " and substringof('" ++ vars.customerSearch ++ "', BusinessPartnerFullName)" else "")
}]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    BusinessPartnerCategory: "1",
    BusinessPartnerFullName: vars.customerPayload.companyName default "",
    FirstName: vars.customerPayload.firstName default "",
    LastName: vars.customerPayload.lastName default "",
    BusinessPartnerIsBlocked: false,
    Language: vars.customerPayload.language default "EN",
    to_BusinessPartnerAddress: [{
        Country: vars.customerPayload.address.country default "",
        Region: vars.customerPayload.address.state default "",
        CityName: vars.customerPayload.address.city default "",
        PostalCode: vars.customerPayload.address.postalCode default "",
        StreetName: vars.customerPayload.address.street default "",
        HouseNumber: vars.customerPayload.address.houseNumber default "",
        to_EmailAddress: [{
            EmailAddress: vars.customerPayload.email default ""
        }],
        to_PhoneNumber: [{
            PhoneNumber: vars.customerPayload.phone default ""
        }]
    }]
}

%dw 2.0
output application/json
---
{
    SalesOrder: vars.invoicePayload.orderId default "",
    BillingDocumentType: vars.invoicePayload.invoiceType default "F2",
    BillingDocumentDate: (vars.invoicePayload.invoiceDate default now()) as String {format: "yyyy-MM-dd"},
    to_Item: (vars.invoicePayload.lineItems default []) map ((item, idx) -> {
        SalesOrderItem: item.itemNumber default ((idx + 1) * 10 as String),
        BillingQuantity: item.quantity default 1,
        BillingQuantityUnit: item.unit default "EA"
    })
}
